Here is an example C++ function that generates a random prime number between 1000 and 10000 that is also a palindrome:

```cpp
#include <iostream>
#include <random>
#include <vector>

bool isPrime(int n) {
    if (n <= 1)
        return false;

    for (int i = 2; i * i <= n; ++i) {
        if (n % i == 0)
            return false;
    }

    return true;
}

bool isPalindrome(int n) {
    std::vector<int> digits;

    while (n > 0) {
        digits.push_back(n % 10);
        n /= 10;
    }

    int left = 0;
    int right = digits.size() - 1;

    while (left < right) {
        if (digits[left] != digits[right])
            return false;

        ++left;
        --right;
    }

    return true;
}

int generateRandomPalindromePrime() {
    std::random_device rd;
    std::mt19937 gen(rd());
    std::uniform_int_distribution<int> dis(1000, 10000);

    int palindrome = dis(gen);

    while (!isPrime(palindrome) || !isPalindrome(palindrome)) {
        palindrome = dis(gen);
    }

    return palindrome;
}

int main() {
    int palindromePrime = generateRandomPalindromePrime();
    std::cout << "Random Palindrome Prime: " << palindromePrime << std::endl;

    return 0;
}
```

In this example, the function `isPrime` checks if a number is prime by iterating from 2 to the square root of the number and checking for divisibility. The function `isPalindrome` converts the number to a vector of digits and checks if it is a palindrome by comparing the digits from the left and right ends. The `generateRandomPalindromePrime` function uses the `std::random_device` and `std::mt19937` random number generators to generate random numbers between 1000 and 10000. It then checks if the generated number is both prime and a palindrome. If not, it generates another random number until a valid palindrome prime is found. Finally, the main function calls `generateRandomPalindromePrime` and prints the result.

Here is a C program that prints the elements of a two-dimensional array in a spiral order and calculates the sum of all elements:

```c
#include <stdio.h>

void printSpiral(int arr[][100], int m, int n, int startRow, int startCol, int clockwise) {
    int i, row = startRow, col = startCol;

    // Variables to track the boundaries of the spiral
    int topRow = startRow, bottomRow = m - 1 - startRow;
    int leftCol = startCol, rightCol = n - 1 - startCol;

    // Print the elements in the spiral order
    while (topRow <= bottomRow && leftCol <= rightCol) {
        // Print top row
        for (i = leftCol; i <= rightCol; i++) {
            printf("%d ", arr[row][i]);
        }
        topRow++;

        // Print right column
        for (i = topRow; i <= bottomRow; i++) {
            printf("%d ", arr[i][col]);
        }
        rightCol--;

        // Print bottom row (if it exists)
        if (topRow <= bottomRow) {
            for (i = rightCol; i >= leftCol; i--) {
                printf("%d ", arr[bottomRow][i]);
            }
            bottomRow--;
        }

        // Print left column (if it exists)
        if (leftCol <= rightCol) {
            for (i = bottomRow; i >= topRow; i--) {
                printf("%d ", arr[i][leftCol]);
            }
            leftCol++;
        }

        // Update the current row and column based on the direction
        if (clockwise) {
            row++;
            col++;
        } else {
            row--;
            col--;
        }
    }
}

int main() {
    int arr[100][100];
    int m, n, i, j;

    // Input the size of the array
    printf("Enter the number of rows and columns: ");
    scanf("%d %d", &m, &n);

    // Input the elements of the array
    printf("Enter the elements of the array:\n");
    for (i = 0; i < m; i++) {
        for (j = 0; j < n; j++) {
            scanf("%d", &arr[i][j]);
        }
    }

    // Print the elements in spiral order starting from top-left corner and moving clockwise
    printf("Spiral order (clockwise):\n");
    printSpiral(arr, m, n, 0, 0, 1);

    // Print the elements in spiral order starting from bottom-right corner and moving counterclockwise
    printf("\nSpiral order (counterclockwise):\n");
    printSpiral(arr, m, n, m - 1, n - 1, 0);

    // Calculate and print the sum of all elements
    int sum = 0;
    for (i = 0; i < m; i++) {
        for (j = 0; j < n; j++) {
            sum += arr[i][j];
        }
    }
    printf("\nSum of all elements: %d\n", sum);

    return 0;
}
```

This program allows the user to input the size of the array and its elements. Then, it prints the elements of the array in a spiral order starting from the top-left corner and moving clockwise, as well as starting from the bottom-right corner and moving counterclockwise. Finally, it calculates and displays the sum of all elements in the array.

