void multiplyArrays(int* array1, int* array2, int* result, int size) {
    int* array1Ptr = new int[size];
    int* array2Ptr = new int[size];
    int* resultPtr = new int[size];

    // Copy the values from the input arrays to the manually allocated arrays
    for (int i = 0; i < size; i++) {
        *(array1Ptr + i) = *(array1 + i);
        *(array2Ptr + i) = *(array2 + i);
    }

    for (int i = 0; i < size; i++) {
        *(resultPtr + i) = *(array1Ptr + i) * *(array2Ptr + i);
