```java
import java.util.Random;

public class StrongPrimeNumber {
    public static void main(String[] args) {
        Random rand = new Random();
        int num = rand.nextInt(1000) + 1; // generate a random number between 1 and 1000

        System.out.println("Random number: " + num);

        if (isPrime(num) && isPrime(sumOfDigits(num))) {
            System.out.println("The number is a strong prime number.");
        } else {
            System.out.println("The number is not a strong prime number.");
        }
    }

    // Function to check if a number is prime
    public static boolean isPrime(int num) {
        if (num <= 1) {
            return false;
        }

        // Check if num is divisible by any number from 2 to sqrt(num)
        for (int i = 2; i <= Math.sqrt(num); i++) {
            if (num % i == 0) {
                return false;
            }
        }

        return true;
    }

    // Function to calculate the sum of digits of a number
    public static int sumOfDigits(int num) {
        int sum = 0;

        while (num > 0) {
            sum += num % 10; // add the last digit to sum
            num /= 10; // remove the last digit
        }

        return sum;
    }
}
```

