import java.util.List;

public class StringConversion {
    private static final int MAX_LENGTH = 2000;

    public static class StringTooLongException extends Exception {
        public StringTooLongException(String message) {
            super(message);
        }
    }

    public static class InvalidCharacterException extends Exception {
        public InvalidCharacterException(String message) {
            super(message);
        }
    }

    public static String[][] convertToList(List<String> strings) throws StringTooLongException, InvalidCharacterException {
        if (strings.size() > Math.pow(10, 6)) {
            throw new IllegalArgumentException("List size exceeds the maximum limit");
        }

        String[][] array = new String[strings.size()][];

        for (int i = 0; i < strings.size(); i++) {
            String string = strings.get(i);

            if (string.length() > MAX_LENGTH) {
                throw new StringTooLongException("String exceeds the maximum length");
            }

            if (!string.matches("[a-zA-Z0-9]+")) {
                throw new InvalidCharacterException("String contains non-alphanumeric characters");
            }

            array[i] = new String[]{string};
        }

        return array;
    }

    public static void main(String[] args) {
        List<String> strings = List.of("abc", "123", "ABc123");

        try {
            String[][] array = convertToList(strings);
            System.out.println("Conversion successful");
