    public static int replaceLetter(String inputString, char letterToReplace, char replacementLetter) {
        int totalReplacements = 0;

        // Split the input string into words
        String[] words = inputString.split("\\s+");

        // Iterate through each word and replace the given letter at the beginning or end of the word
        for (int i = 0; i < words.length; i++) {
            String word = words[i];
            char[] characters = word.toCharArray();

            // Check if the first character is the letter to replace
            if (Character.toLowerCase(characters[0]) == Character.toLowerCase(letterToReplace)) {
                characters[0] = getReplacementCharacter(characters[0], -2);
                totalReplacements++;
            }

            // Check if the last character is the letter to replace
            if (Character.toLowerCase(characters[characters.length - 1]) == Character.toLowerCase(letterToReplace)) {
                characters[characters.length - 1] = getReplacementCharacter(characters[characters.length - 1], 2);
                totalReplacements++;
            }

            words[i] = new String(characters);
        }

        // Join the words back into a string
        String replacedString = String.join(" ", words);
        System.out.println("Replaced string: " + replacedString);

        return totalReplacements;
    }

    public static char getReplacementCharacter(char letter, int offset) {
        char replacement = (char) (letter + offset);

        // Wrap around to the beginning/end of the alphabet if necessary
        if (replacement < 'a') {
            replacement = (char) (replacement + 26);
        } else if (replacement > 'z') {
            replacement = (char) (replacement - 26);
        }

        return replacement;
    }
}
