function reverseArray(arr) {
  if (arr.length === 0 || !Array.isArray(arr)) {
    return arr;
  }

  // Check if the array is already sorted
  let isSorted = true;
  for (let i = 0; i < arr.length - 1; i++) {
    if (arr[i] > arr[i + 1]) {
      isSorted = false;
      break;
    }
  }

  if (isSorted) {
    return arr;
  }

  // Remove duplicates
  let uniqueArr = [];
  for (let i = 0; i < arr.length; i++) {
    let num = Math.trunc(arr[i]);
    if (!uniqueArr.includes(num)) {
      uniqueArr.push(num);
    }
  }

  // Reverse the array in-place
  let start = 0;
  let end = uniqueArr.length - 1;
  while (start < end) {
    let temp = uniqueArr[start];
    uniqueArr[start] = uniqueArr[end];
    uniqueArr[end] = temp;
    start++;
    end--;
  }

  return uniqueArr;
}

