function capitalizeWordsAndSwapCases(str) {
  // Remove numbers from the string
  str = str.replace(/[0-9]/g, '');

  // Split the string into an array of words
  const words = str.split(' ');

  // Loop through each word
  for (let i = 0; i < words.length; i++) {
    let word = words[i];

    // Remove punctuation from the end of the word
    const lastChar = word[word.length - 1];
    if (lastChar.match(/[^\w\s]/)) {
      word = word.slice(0, -1);
    }

    // Capitalize the word if it starts with a vowel
    if (word[0].match(/[aeiou]/i)) {
      word = word.toUpperCase();
    } else {
      // Capitalize the first letter of the word
      word = word.charAt(0).toUpperCase() + word.slice(1);
    }

    // Swap cases for the rest of the characters in the word
    const characters = word.split('');
    for (let j = 1; j < characters.length; j++) {
      if (characters[j].match(/[a-z]/)) {
        characters[j] = characters[j].toUpperCase();
      } else {
        characters[j] = characters[j].toLowerCase();
      }
    }

    // Join the characters back into a word
    words[i] = characters.join('');
  }

  // Join the words back into a string
  return words.join(' ');
}

