public class SubstringChecker {

    public static boolean isSubstringAndSubsequence(String str1, String str2) {
        if (str1.isEmpty()) {
            return true; // An empty string is always a substring and subsequence of any string
        }

        int i = 0; // Pointer for str1
        int j = 0; // Pointer for str2

        while (j < str2.length()) {
            if (str1.charAt(i) == str2.charAt(j)) {
                i++; // Move to the next character in str1
                if (i == str1.length()) {
                    return true; // Reached the end of str1, it is a substring and subsequence of str2
                }
            }

            j++; // Move to the next character in str2
        }

        return false; // Didn't find a complete match of str1 in str2
    }

    public static void main(String[] args) {
        String str1 = "abc";
        String str2 = "abcde";
        System.out.println(isSubstringAndSubsequence(str1, str2)); // true

        str1 = "abc";
        str2 = "def";
        System.out.println(isSubstringAndSubsequence(str1, str2)); // false

        str1 = "abc";
        str2 = "aabbcc";
        System.out.println(isSubstringAndSubsequence(str1, str2)); // true

        str1 = "";
        str2 = "abc";
        System.out.println(isSubstringAndSubsequence(str1, str2)); // true

        str1 = "abc";
        str2 = "";
        System.out.println(isSubstringAndSubsequence(str1, str2)); // false
    }
}
