      word.length > 3 &&
      word.match(/^[a-z]*$/g) &&
      /[aeiou]/i.test(word) &&
      /[b-df-hj-np-tv-z]{1}[aeiou]{1}[b-df-hj-np-tv-z]{1}/i.test(word)
