function calculateFactorial(num) {
  // Handle negative numbers
  if (num < 0) {
    return "Error: Cannot calculate factorial of a negative number.";
  }

  // Handle decimal numbers
  if (num % 1 !== 0) {
    return "Error: Decimal numbers are not allowed.";
  }

  // Handle very large numbers
  if (num > Number.MAX_SAFE_INTEGER) {
    return "Error: Number is too large to calculate factorial.";
  }

  // Calculate factorial
  let factorial = 1;
  for (let i = 2; i <= num; i++) {
    factorial *= i;
  }

  return factorial;
}

