from django.db import models

class Author(models.Model):
    name = models.CharField(max_length=100)
    email = models.EmailField(unique=True)
    unique_identifier = models.CharField(max_length=100, unique=True)

    def __str__(self):
        return self.name

class BlogPost(models.Model):
    STATUS_CHOICES = [
        ('draft', 'Draft'),
        ('published', 'Published'),
    ]

    title = models.CharField(max_length=100)
    content = models.TextField()
    status = models.CharField(max_length=20, choices=STATUS_CHOICES, default='draft')
    published_date = models.DateField()
    author = models.ForeignKey(Author, on_delete=models.CASCADE)

    def __str__(self):
        return self.title

    @classmethod
    def get_posts_within_date_range(cls, start_date, end_date):
        return cls.objects.filter(published_date__range=[start_date, end_date])

    @classmethod
    def get_total_published_posts_by_author(cls):
        return cls.objects.filter(status='published').values('author__name').annotate(total_posts=models.Count('id'))

    @classmethod
    def get_average_length_of_posts_by_author(cls):
        return cls.objects.filter(status='published').values('author__name').annotate(avg_length=models.Avg(models.Length('content')))

    @classmethod
    def get_most_recent_post_by_author(cls):
        return cls.objects.filter(status='published').order_by('-published_date').distinct('author')

    @classmethod
    def get_oldest_post_by_author(cls):
        return cls.objects.filter(status='published').order_by('published_date').distinct('author')

    @classmethod
    def get_author_with_highest_avg_length(cls):
        return cls.objects.filter(status='published').values('author__name').annotate(avg_length=models.Avg(models.Length('content'))).order_by('-avg_length').first()

    @classmethod
    def get_author_with_lowest_avg_length(cls):
        return cls.objects.filter(status='published').values('author__name').annotate(avg_length=models.Avg(models.Length('content'))).order_by('avg_length').first()
