```
class Memoization:
    def __init__(self):
        self.memo = {}

    def get(self, n):
        if n in self.memo:
            return self.memo[n]
        else:
            return None

    def put(self, n, value):
        self.memo[n] = value


def fibonacci(n, memoization):
    if n == 0:
        return 0
    elif n == 1:
        return 1
    else:
        memo_value = memoization.get(n)
        if memo_value is not None:
            return memo_value
        else:
            fib_value = fibonacci(n - 1, memoization) + fibonacci(n - 2, memoization)
            memoization.put(n, fib_value)
            return fib_value


def generate_fibonacci_series(n):
    memoization = Memoization()
    fibonacci_series = []
    for i in range(n + 1):
        fibonacci_series.append(fibonacci(i, memoization))
    return fibonacci_series
```

