                    repetition = int(repetition)
                else:
                    # If no repetition has been specified, default to 1
                    repetition = 1
                if current_word in word_counts:
                    # If the word already exists in the dictionary, add the repetition to the existing value
                    word_counts[current_word] += repetition
                else:
                    # If the word does not exist in the dictionary, add it with the repetition as the value
                    word_counts[current_word] = repetition
                # Add the word to the list of words in the order they appear
                words.append(current_word)
                current_word = ''
        elif char.isdigit():
            # If a digit is encountered, add it to the repetition string
            repetition += char
        else:
            # If any other character is encountered, add it to the current word
            current_word += char

    # If a word has not been completed after the last character, add it to the list of words
    if current_word != '':
        words.append(current_word)

