#include <iostream>
#include <climits>

int findMax(int arr[], int start, int end) {
    if (start > end) {
        // Array is empty, return special value
        return INT_MIN;
    }

    if (start == end) {
        // Only one element in the array, return it
        return arr[start];
    }

    int mid = (start + end) / 2;
    int maxLeft = findMax(arr, start, mid);
    int maxRight = findMax(arr, mid + 1, end);

    return std::max(maxLeft, maxRight);
}

