```cpp
#include <iostream>
#include <string>

bool isPalindromic(const std::string& str) {
    int start = 0;
    int end = str.length() - 1;
    while (start < end) {
        if (str[start] != str[end])
            return false;
        start++;
        end--;
    }
    return true;
}

bool isValidSubstring(const std::string& str) {
    if (str.length() < 5)
        return false;

    bool digitFound = false;
    for (char ch : str) {
        if (isdigit(ch))
            digitFound = true;
    }
    if (!digitFound)
        return false;

    for (int i = 1; i < str.length(); i++) {
        if (str[i] <= str[i - 1])
            return false;
    }
    return true;
}

std::string findLongestCommonSubstring(const std::string& str1, const std::string& str2) {
    int maxLength = 0;
    int maxStart = 0;

    int n = str1.length();
    int m = str2.length();

    int dp[n + 1][m + 1];
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= m; j++) {
            if (i == 0 || j == 0)
                dp[i][j] = 0;
            else if (str1[i - 1] == str2[j - 1]) {
                dp[i][j] = dp[i - 1][j - 1] + 1;
                if (dp[i][j] > maxLength && isValidSubstring(str1.substr(i - dp[i][j], dp[i][j]))) {
                    maxLength = dp[i][j];
                    maxStart = i - dp[i][j];
                }
            } else
                dp[i][j] = 0;
        }
    }

    return str1.substr(maxStart, maxLength);
}

int main() {
    std::string str1, str2;
    std::cout << "Enter the first string: ";
    std::cin >> str1;
    std::cout << "Enter the second string: ";
    std::cin >> str2;

    std::string longestCommonSubstring = findLongestCommonSubstring(str1, str2);

    if (longestCommonSubstring.empty())
        std::cout << "No common substring found.";
    else
        std::cout << "Longest common substring: " << longestCommonSubstring;

    return 0;
}
