            print(f"Species: {animal.species}")
            if isinstance(animal, Mammal):
                print(f"Number of legs: {animal.num_legs}")
            elif isinstance(animal, Bird):
                print(f"Wingspan: {animal.wingspan}")
            elif isinstance(animal, Reptile):
                print(f"Length: {animal.length}")
            print(f"Remaining lifespan: {animal.calculate_lifespan()}")
            print()

    def calculate_average_age(self):
        total_age = 0
        num_animals = len(self.animals)
        if num_animals == 0:
            return 0
        else:
            for animal in self.animals:
                total_age += animal.age
            average_age = total_age / num_animals
            return average_age

    def feed_animals(self):
        for animal in self.animals:
            try:
                if isinstance(animal, Mammal):
                    animal.feed()
                elif isinstance(animal, Bird):
                    animal.peck()
                elif isinstance(animal, Reptile):
                    animal.bask()
            except Exception as e:
