import java.util.Arrays;
import java.util.Random;
import java.util.Scanner;

public class BubbleSort {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter the size of the array: ");
        int size = scanner.nextInt();

        int[] array = new int[size];

        System.out.println("Choose an option: ");
        System.out.println("1. Manual input");
        System.out.println("2. Random generation");

        int option = scanner.nextInt();

        if (option == 1) {
            System.out.println("Enter the array elements: ");
            for (int i = 0; i < size; i++) {
                array[i] = scanner.nextInt();
            }
        } else if (option == 2) {
            System.out.println("Enter the range of random generation (start end): ");
            int start = scanner.nextInt();
            int end = scanner.nextInt();

            Random random = new Random();
            for (int i = 0; i < size; i++) {
                array[i] = random.nextInt(end - start + 1) + start;
            }
        } else {
            System.out.println("Invalid option");
            return;
        }

        System.out.println("Choose a sorting order: ");
        System.out.println("1. Ascending");
        System.out.println("2. Descending");

        int order = scanner.nextInt();

        if (order == 1) {
            bubbleSortAscending(array);
        } else if (order == 2) {
            bubbleSortDescending(array);
        } else {
            System.out.println("Invalid order");
            return;
        }

        System.out.println("Sorted array: " + Arrays.toString(array));
    }

    public static void bubbleSortAscending(int[] array) {
        int n = array.length;
        int comparisons = 0;
        int swaps = 0;

        for (int i = 0; i < n - 1; i++) {
            boolean swapped = false;

            for (int j = 0; j < n - i - 1; j++) {
                if (array[j] > array[j + 1]) {
                    swap(array, j, j + 1);
                    swapped = true;
                    swaps++;
                }
                comparisons++;
            }

            if (!swapped) {
                break;
            }

            System.out.println("Pass " + (i + 1) + ": " + Arrays.toString(array));
        }

        System.out.println("Comparisons: " + comparisons);
        System.out.println("Swaps: " + swaps);
    }

    public static void bubbleSortDescending(int[] array) {
        int n = array.length;
        int comparisons = 0;
        int swaps = 0;

        for (int i = 0; i < n - 1; i++) {
            boolean swapped = false;

            for (int j = 0; j < n - i - 1; j++) {
                if (array[j] < array[j + 1]) {
                    swap(array, j, j + 1);
                    swapped = true;
                    swaps++;
                }
                comparisons++;
            }

            if (!swapped) {
                break;
            }

            System.out.println("Pass " + (i + 1) + ": " + Arrays.toString(array));
        }

        System.out.println("Comparisons: " + comparisons);
        System.out.println("Swaps: " + swaps);
    }

    public static void swap(int[] array, int i, int j) {
        int temp = array[i];
        array[i] = array[j];
        array[j] = temp;
    }
}

To create a new dictionary that satisfies the given requirements, we can use a combination of a list and a dictionary.

The list will serve as a lookup table, where each index represents a key and the corresponding value at that index represents the value associated with that key. This will allow us to perform operations in constant time since we can access any entry directly by its index.

The dictionary will be used to keep track of the indices of the keys in the list. This will allow us to quickly check if a key exists and to update or remove entries in constant time.

Here is an implementation in Python:

```python
class MyDictionary:
    def __init__(self):
        self.lookup = [None] * 1000  # Initialize list with None values
        self.indices = {}  # Initialize dictionary

    def add_entry(self, key, value):
        if not isinstance(key, int) or key <= 0 or key > 1000:
            raise ValueError("Key must be a positive integer between 1 and 1000")
        if not isinstance(value, str) or not value.islower() or not value:
            raise ValueError("Value must be a non-empty lowercase string")
        if key in self.indices:
            raise ValueError("Key already exists")

        index = len(self.indices)  # Get the next available index
        self.lookup[index] = value  # Add value to the list
        self.indices[key] = index  # Add key-index pair to the dictionary

    def get_value(self, key):
        index = self.indices.get(key)
        return self.lookup[index] if index is not None else None

    def update_value(self, key, new_value):
        if key in self.indices:
            index = self.indices[key]
            self.lookup[index] = new_value

    def remove_entry(self, key):
        if key in self.indices:
            index = self.indices.pop(key)
            self.lookup[index] = None

    def key_exists(self, key):
