#include <iostream>
#include <vector>

bool isPrime(int num) {
    if (num <= 1)
        return false;

    for (int i = 2; i * i <= num; i++) {
        if (num % i == 0)
            return false;
    }

    return true;
}

bool hasDigit5(int num) {
    while (num != 0) {
        if (num % 10 == 5)
            return true;
        num /= 10;
    }
    return false;
}

bool isDivisibleBy3(int num) {
    return num % 3 == 0;
}

double calculateAverage(const std::vector<int>& numbers, int n, int sum, int count) {
    if (n == 0) {
        if (count == 0) {
            std::cerr << "Error: No valid numbers provided." << std::endl;
            exit(1);
        }
        return static_cast<double>(sum) / count;
    }

    int num;
    std::cout << "Enter a number: ";
    std::cin >> num;

    if (!isPrime(num) && !hasDigit5(num) && !isDivisibleBy3(num)) {
        sum += num;
        count++;
    }

    return calculateAverage(numbers, n - 1, sum, count);
}

int main() {
