public class FirstOccurrence {

    public static int findFirstOccurrence(int[] arr, int target) {
        int left = 0;
        int right = arr.length - 1;
        int result = -1;

        while (left <= right) {
            int mid = left + ((right - left) >> 1);

            // Check if the mid element is equal to the target
            if (arr[mid] == target) {
                result = mid;

                // Move the right pointer to the left to find the first occurrence
                right = mid - 1;
            }
            // Check if the mid element is greater than the target
            else if (arr[mid] > target) {
                right = mid - 1;
            }
            // Check if the mid element is less than the target
            else {
                left = mid + 1;
            }
        }

        return result;
    }

    public static void main(String[] args) {
        int[] arr = {1, 2, 2, 3, 3, 3, 4, 5, 6, 6};
        int target = 3;
        int index = findFirstOccurrence(arr, target);

        if (index == -1) {
            System.out.println("Target element not found in the array");
        } else {
            System.out.println("Index of first occurrence: " + index);
        }
    }
}
```

