import java.util.Scanner;

public class PalindromeChecker {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();
        scanner.close();

        String processedInput = removeSpecialCharsAndSpaces(input).toLowerCase();

        int start = 0;
        int end = processedInput.length() - 1;

        while (start < end) {
            if (processedInput.charAt(start) != processedInput.charAt(end)) {
                System.out.println("No");
                return;
            }
            start++;
            end--;
        }

        System.out.println("Yes");
    }

    private static String removeSpecialCharsAndSpaces(String input) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < input.length(); i++) {
            char ch = input.charAt(i);
            if (Character.isLetter(ch) || Character.isDigit(ch)) {
                sb.append(ch);
            }
        }
        return sb.toString();
    }
}
