public class FibonacciSequence {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter the limit for the Fibonacci sequence: ");
        int limit = scanner.nextInt();

        if (limit <= 0) {
            System.out.println("Invalid input. Limit must be a positive integer.");
            return;
        }

        System.out.println("Fibonacci sequence up to " + limit + ":");

        // Initialize memoization array
        long[] memo = new long[limit + 1];
        memo[0] = 0;
        memo[1] = 1;

        long sumOfEvenNumbers = 0;

        for (int i = 0; i <= limit; i++) {
            long fibonacciNumber = fibonacci(i, memo);

            if (fibonacciNumber % 2 == 0) {
                sumOfEvenNumbers += fibonacciNumber;
            }

            System.out.print(fibonacciNumber + " ");
        }

        System.out.println("\nSum of even numbers: " + sumOfEvenNumbers);
    }

    private static long fibonacci(int n, long[] memo) {
        if (n == 0 || n == 1) {
            return memo[n];
        }

        if (memo[n] == 0) {
            memo[n] = fibonacci(n - 1, memo) + fibonacci(n - 2, memo);
        }

        return memo[n];
    }
}

