    public static boolean isPalindrome(int num) {
        int original = num;
        int reverse = 0;

        while (num != 0) {
            int remainder = num % 10;
            reverse = reverse * 10 + remainder;
            num /= 10;
        }

        return original == reverse;
    }

    // Function to find the largest prime number within a range, excluding palindromes
    public static int findLargestPrime(int start, int end) {
        int largestPrime = -1;

        for (int i = start; i <= end; i++) {
            if (isPrime(i) && !isPalindrome(i)) {
                largestPrime = i;
            }
        }

        return largestPrime;
    }

    // Function to count the number of prime numbers within a range, excluding palindromes
    public static int countPrimes(int start, int end) {
        int primeCount = 0;

        for (int i = start; i <= end; i++) {
            if (isPrime(i) && !isPalindrome(i)) {
                primeCount++;
            }
        }

        return primeCount;
    }
}
