Here is an implementation of Quick Sort in Java that meets all the requirements:

```java
import java.util.Arrays;

public class QuickSort {

    public static void main(String[] args) {
        int[] arr = {5, -10, 3, 7, 2, 9, -1, 0, 5, 2, 10, -5, 3, 7, 1, -2, -10, 9, 4, 6, -4, 8, -7, -8, 6, 0, 1, -6, -3, -9, 4, 8, -5, 10, -2, 0, -9, -7, 7, 1, -4, 6, -8, 9, 2, -6, -1, 8, -3, 3, 4};

        QuickSort quickSort = new QuickSort();
        quickSort.sort(arr);

        System.out.println("Sorted array: " + Arrays.toString(arr));
    }

    public void sort(int[] arr) {
        if (arr == null || arr.length == 0) {
            throw new IllegalArgumentException("Input array must not be empty or null");
        }

        quickSort(arr, 0, arr.length - 1);
    }

    private void quickSort(int[] arr, int low, int high) {
        if (low < high) {
            int pivotIndex = partition(arr, low, high);
            quickSort(arr, low, pivotIndex - 1);
            quickSort(arr, pivotIndex + 1, high);
        }
    }

    private int partition(int[] arr, int low, int high) {
        int pivot = arr[high];
        int i = low - 1;

        for (int j = low; j < high; j++) {
            if (arr[j] <= pivot) {
                i++;
                swap(arr, i, j);
            }
        }

        swap(arr, i + 1, high);
        return i + 1;
    }

    private void swap(int[] arr, int i, int j) {
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }
}
```

