```java
import java.util.EmptyStackException;

class CustomStack {
    private char[] stack;
    private int top;

    public CustomStack(int size) {
        stack = new char[size];
        top = -1;
    }

    public void push(char c) {
        stack[++top] = c;
    }

    public char pop() {
        return stack[top--];
    }

    public boolean isEmpty() {
        return top == -1;
    }
}

class BracketChecker {
    public static boolean checkBrackets(String input) {
        CustomStack stack = new CustomStack(input.length());

        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);

            if (isOpeningBracket(c)) {
                stack.push(c);
            } else if (isClosingBracket(c)) {
                try {
                    char top = stack.pop();

                    if (!isMatchingBracket(top, c)) {
                        return false;
                    }
                } catch (EmptyStackException e) {
                    return false;
                }
            }
        }

        return stack.isEmpty();
    }

    private static boolean isOpeningBracket(char c) {
        return c == '(' || c == '[' || c == '{';
    }

    private static boolean isClosingBracket(char c) {
        return c == ')' || c == ']' || c == '}';
    }

    private static boolean isMatchingBracket(char opening, char closing) {
        return (opening == '(' && closing == ')')
                || (opening == '[' && closing == ']')
                || (opening == '{' && closing == '}');
    }
}

public class Main {
    public static void main(String[] args) {
        String input1 = "({})";
        String input2 = "({)}";
        String input3 = "({[})";
        String input4 = "({[()]})";
        String input5 = "({[()})";

        System.out.println(BracketChecker.checkBrackets(input1)); // true
        System.out.println(BracketChecker.checkBrackets(input2)); // false
        System.out.println(BracketChecker.checkBrackets(input3)); // false
        System.out.println(BracketChecker.checkBrackets(input4)); // true
        System.out.println(BracketChecker.checkBrackets(input5)); // false
    }
}
```

The `CustomStack` class represents a custom stack data structure that stores characters. The `push` method adds a character to the top of the stack, the `pop` method removes and returns the top character, and the `isEmpty` method checks if the stack is empty.

